<section class="dashboard-section"><div class="section-header"><div><span class="section-kicker">Relation commerciale</span><h2>Portefeuille clients</h2><p class="ui-page-intro">Retrouvez l’activité commerciale et financière consolidée de chaque client.</p></div><a class="btn btn-primary" href="<?= url('clients/create'); ?>"><i class="bi bi-plus-circle"></i> Ajouter un client</a></div><?php if ($m=Session::flash('success')): ?><div class="alert alert-success"><?= e($m); ?></div><?php endif; ?></section>
<section class="panel"><div class="panel-header"><div><span class="section-kicker">Suivi client</span><h3>Clients enregistrés</h3></div><span class="badge badge-neutral"><?= count($clients); ?> clients</span></div><div class="filters-bar"><label>Recherche <input type="search" data-table-search data-target="#clients-table" placeholder="Code, client ou contact"></label></div><div class="table-responsive"><table class="data-table" id="clients-table"><thead><tr><th>Code</th><th>Client</th><th>Contact principal</th><th>Devis</th><th>Commandes</th><th class="text-right">Montant facturé</th><th class="text-right">Montant encaissé</th><th>Statut</th></tr></thead><tbody><?php foreach($clients as $client): ?><tr><td><strong><?= e($client['client_code']); ?></strong></td><td><?= e($client['name']); ?><small class="muted-line"><?= e($client['address'] ?: 'Adresse non renseignée'); ?></small></td><td><?= e($client['contact_name'] ?: 'Non renseigné'); ?><small class="muted-line"><?= e($client['phone'] ?: 'Téléphone non renseigné'); ?></small></td><td><?= (int)$client['quotations_count']; ?></td><td><?= (int)$client['orders_count']; ?></td><td class="text-right"><?= money($client['invoiced_total']); ?></td><td class="text-right"><?= money($client['paid_total']); ?></td><td><span class="badge <?= status_badge_class($client['status']); ?>"><?= e(status_label($client['status'])); ?></span></td></tr><?php endforeach; ?></tbody></table></div></section>
